import sys
def main():
    data=sys.stdin.read().strip().split()
    if not data:
        return
    it=iter(data)
    T=int(next(it))
    out_lines=[]
    for _ in range(T):
        n=int(next(it))
        odds=[]
        evens=[]
        for _ in range(n):
            x=int(next(it))
            if x%2:
                odds.append(str(x))
            else:
                evens.append(str(x))
        out_lines.append(' '.join(odds))
        out_lines.append(' '.join(evens))
    sys.stdout.write('\n'.join(out_lines))
if __name__=='__main__':
    main()

