const fs = require('fs');
const input = fs.readFileSync(0, 'utf-8').trim().split(/\s+/);
let idx = 0;
const T = Number(input[idx++]);
let out = [];
for (let t = 0; t < T; ++t) {
  const n = Number(input[idx++]);
  const odds = [];
  const evens = [];
  for (let i = 0; i < n; ++i) {
    const x = Number(input[idx++]);
    if (x % 2 !== 0) odds.push(x);
    else evens.push(x);
  }
  out.push(odds.join(' '));
  out.push(evens.join(' '));
}
